For whatever reason, it seems that lfortran is trying to override FreeBSD's definition of `struct dl_phdr_info`.   Here is FreeBSD's `dl_phdr_info`.

```
struct dl_phdr_info
{
        Elf_Addr dlpi_addr;                     /* module relocation base */
        const char *dlpi_name;                  /* module name */
        const Elf_Phdr *dlpi_phdr;              /* pointer to module's phdr */
        Elf_Half dlpi_phnum;                    /* number of entries in phdr */
        unsigned long long int dlpi_adds;       /* total # of loads */
        unsigned long long int dlpi_subs;       /* total # of unloads */
        size_t dlpi_tls_modid;
        void *dlpi_tls_data;
};
```

while `src/libasr/runtime/lfortran_intrinsics.c` contains

```
#ifdef HAVE_LFORTRAN_LINK
// For dl_iterate_phdr() functionality
#  include <link.h>
struct dl_phdr_info {
    ElfW(Addr) dlpi_addr;
    const char *dlpi_name;
    const ElfW(Phdr) *dlpi_phdr;
    ElfW(Half) dlpi_phnum;
};
```","reactions":{"url":"https://api.github.com/repos/lfortran/lfortran/issues/3895/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/lfortran/lfortran/issues/3895/timeline","performed_via_github_app":null,"state_reason":null}}

